var e=[{id:`L2_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`좋아, 일단 피도 멎었고 의식도 회복했어.`,JPN:`よし、とりあえずは血も止まって、意識も取り戻してる。`,ENG:`Okay. The bleeding's stopped and she's regained consciousness.`,TWN:`好了，血止住了，人也恢復意識了。`},stage:{bg:`BACKSTREET2`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`STAFF_CANARY_NULL_NULL`,text:{KOREA:`구급차 불렀어. 금방 올거야.`,JPN:`救急車を呼んだわ。すぐ来るはずよ。`,ENG:`I called the ambulance. It should be here soon.`,TWN:`我叫了救護車，應該很快就到了。`},stage:{bg:`BACKSTREET2`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L6_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`……코치.`,JPN:`……コーチ。`,ENG:`...Coach.`,TWN:`……教練。`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`라이카 양, 이제 정신이 드나?`,JPN:`ライカ君、気がついたか？`,ENG:`Laika, are you okay?`,TWN:`萊卡，你醒了？`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`꼬맹… 이는……?`,JPN:`おこ……ちゃまは……？`,ENG:`What about... the kid...?`,TWN:`小鬼…人呢……？`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`자네를 공격한 자를 쫓아갔네.`,JPN:`君を攻撃した者を追いかけていった。`,ENG:`She went after whoever attacked you.`,TWN:`她去追攻擊你的人了。`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`말해보게, 라이카 양. 어째서 저들이 자네를 공격한 거지?`,JPN:`話してくれ、ライカ君。どうしてあの者たちが君を攻撃したんだ？`,ENG:`Talk to me, Laika. Why did they attack you?`,TWN:`萊卡，這是怎麼回事？那些人為什麼要攻擊你？`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`……출신 때문에.`,JPN:`……出身。`,ENG:`...My background.`,TWN:`……因為出身。`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`내 출신 때문일 거야.`,JPN:`たぶん私の出身のせいだと思う。`,ENG:`It's because of where I'm from.`,TWN:`他們攻擊我是因為我的出身。`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`출신이라고?`,JPN:`出身？`,ENG:`Where you're from?`,TWN:`因為你的出身？`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`잠깐! 사장님! 저길 봐!`,JPN:`ちょっと！　社長！　あそこを見て！`,ENG:`Wait a minute! Boss! Look over there!`,TWN:`老闆！你看！`},stage:{bg:`BACKSTREET2`,slots:{L:{char_id:`MINA_FENRIR_CHIEF_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L22_1`,type:`dialog`,speaker:`MINA_FENRIR_CHIEF_NULL`,text:{KOREA:`노엘이랑 펠리세트가 향한 방향이야……!`,JPN:`ノエルとフェリセットが向かった方向だよ……！`,ENG:`It's where Noelle and Félicette went...!`,TWN:`那是洛艾兒和費莉塞特所在的方向……！`},stage:{bg:`CHARADE2_01`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`STAFF_CANARY_NULL_NULL`,text:{KOREA:`벼, 벼락이라도 떨어진 걸까요?`,JPN:`か、雷でも落ちたんでしょうか？`,ENG:`I-is there lightning striking down?`,TWN:`是打雷嗎？`},stage:{bg:`CHARADE2_01`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`자연 현상 같은 게 아닐세.`,JPN:`自然現象などではないな。`,ENG:`It is not a natural phenomenon.`,TWN:`應該不是自然現象。`},stage:{bg:`CHARADE2_01`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:`USER_ADMIN_NULL_NULL`,text:{KOREA:`아마도 어떤 에너지가 다른 에너지로 변환되는 과정 같아.`,JPN:`たぶん、あるエネルギーが他のエネルギーへと変換されているんだろう。`,ENG:`It appears to be the process of converting one type of energy into another.`,TWN:`似乎是某種能量轉換成其他能量的過程。`},stage:{bg:`CHARADE2_01`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`STAFF_CANARY_NULL_NULL`,text:{KOREA:`에너지의 변환이라고요?`,JPN:`エネルギーの変換？`,ENG:`Converting energy?`,TWN:`能量轉換？`},stage:{bg:`CHARADE2_01`,slots:{L:null,C:null,R:null}}}];export{e as default};